VALUES
  ('heelevel3-0a2fc18c-moex-00054', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '假設美麗國廠商在本國與外國僱用勞工生產成衣，在某一固定產量下，每位本國與外國勞工的邊 際生產力分別為10與5，每位本國與外國勞工的薪資分別為5與2。下列敘述何者錯誤？', '["在此固定產量下，以外國勞工替代本國勞工的邊際技術替代率為0.5", "若廠商增加1位外國勞工，同時減少1位本國勞工，產量會下降", "維持相同成本，廠商增加外國勞工的僱用，減少本國勞工的僱用，產量會下降", "本國勞工每塊錢的邊際生產力低於外國勞工"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00055', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '有關獨占性競爭廠商，下列何者錯誤？', '["獨占性競爭廠商會從事產品異質化，但創意也很容易被模仿", "獨占性競爭廠商有一定的訂價權力，隨著顧客忠誠度越高、訂價權力越大", "獨占性競爭廠商的訂價權力讓其在長期得以享受正的經濟利潤", "獨占性競爭廠商可以透過廣告來傳遞其產品異質化的訊息"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00056', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '假設政府通過一法令，要求廠商必須給予受雇勞工每小時200元的額外福利，若此一政策造成勞 動需求與勞動供給同時變動，則勞動市場之均衡有何變化？', '["均衡工資變動方向不確定，均衡勞動雇用量下降", "均衡工資變動方向不確定，均衡勞動雇用量上升", "均衡工資上升，均衡勞動雇用量變動方向不確定", "均衡工資下降，均衡勞動雇用量變動方向不確定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00057', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '小丁是財富的風險愛好者（risklover），則下列何者正確？', '["小丁財富的邊際效用會隨著財富的增加而遞減", "小丁財富的邊際效用不會隨著財富的增加而改變", "小丁財富的邊際效用會隨著財富的增加而遞增", "小丁財富的邊際效用會隨著財富的增加先遞減再遞增"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00058', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '考慮一個經濟體系包含了兩個消費者、兩個生產要素以及兩個廠商。則此經濟體系的契約曲線 （contractcurve）會滿足下列何種條件？', '["在契約曲線上的每一點，必為兩個消費者無異曲線的相交點", "在契約曲線上的每一點，必有一個生產要素沒有用完", "在契約曲線上的每一點，必是該經濟體系最有效率的分配組合點", "在契約曲線上的每一點，必滿足第二社會福利定理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00059', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '假設在一個完全競爭市場裡，整體廠商生產X的邊際成本為0.2X，同時每增加1單位X產生的 污染物所造成的社會損害成本為2元，消費者對X的需求曲線為P=6-0.2X，若政府以課污染稅的 方式欲使外部成本內部化，則每單位X應課之從量稅及此時之產量為何？', '["（1,10）", "（1,20）", "（2,20）", "（2,10） 32260 32760"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00060', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '甲國國民生產雞蛋並提供電影娛樂服務。一年內，他們生產了價值 1,000 萬元的雞蛋，其中 800 萬元的雞蛋供國內所需，另外200萬元的雞蛋外銷至乙國。甲國國民在國內外共提供了價值500 萬元的電影娛樂服務，其中在甲國提供價值200萬元，在乙國提供價值300萬元。此外，他們從 乙國購買了價值400萬元的天然氣。下列敘述何者正確？', '["國民生產毛額（GNP）為1,000萬元", "國內生產毛額（GDP）為1,500萬元", "出口淨額（netexports）為100萬元", "經常帳餘額（currentaccountbalance）為100萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00061', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '當緊縮缺口存在時，根據附加預期的菲力普曲線（expectations-augmentedPhillipscurve），下列何 者正確？', '["預期通貨膨脹率大於實際通貨膨脹率", "預期通貨膨脹率等於實際通貨膨脹率", "預期通貨膨脹率小於實際通貨膨脹率", "預期通貨膨脹率與實際通貨膨脹率的關係不確定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00062', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '梭羅模型（Solow model）假設生產函數具有規模報酬不變（constant return to scale）的性質。若 Y、K、L分別代表產出、資本與勞動，則下列生產函數何者不具有規模報酬不變的性質？', '["Y=K0.3L0.7", "Y=KL", "Y= KL", "Y=K+L"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL),
  ('heelevel3-0a2fc18c-moex-00063', 'heelevel3-0a2fc18c', 'heelevel3-0a2fc18c-moex-113-d3ff7f6b', 'sub-heelevel3-0a2fc18c-03', NULL, 'single_choice', '有一修正凱因斯模型如下： 消費函數：C(Y－T)=0.8(Y－T)； 投資需求函數：I=306－28r； 政府支出：G=0； 稅收函數：T=T +0.1Y，T =0；', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:47+00:00", "source_pdf_sha1": "5eb67721d51d", "answer_pdf_sha1": "0e7bbb6b55ef", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "327", "s": "0807", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "經濟學", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "heelevel3", "civil_category": "經建行政"}'::jsonb, NULL)
